import source

def test_pascal_triangle_trailing_element():
    result = source.pascal(3)
    expected = [[1], [1, 1], [1, 2, 1]]
    assert len(result) == 3, "The number of rows should be 3."
    for i, row in enumerate(result):
        assert len(row) == i + 1, f"Row {i + 1} should have length {i + 1}."
        for j, value in enumerate(row):
            assert value == expected[i][j], f"Element {j + 1} in row {i + 1} should be {expected[i][j]} but is {value}."
